### 2. 新增进度渲染函数 (在 `_run_plan_and_code` 之前添加)

```python
def _render_progress_html(current_step: int, error: bool = False) -> str:
    """
    current_step: 
    0 = Idle/Start
    1 = Preview Done, Planning...
    2 = Plan Done, Coding...
    3 = All Done
    """
    steps = ["Data Preview", "Processing Plan", "Code Generation"]
    html = '<div class="step-container">'

    for idx, name in enumerate(steps):
        # Determine status
        if idx < current_step:
            status_class = "done"
            icon = "✓"
        elif idx == current_step:
            if error:
                status_class = "active" # keep active style but maybe red color handled externally, or keep simple
                icon = "✕"
            elif current_step == 3: # Should not hit here if loop logic is correct
                 status_class = "done"
                 icon = "✓"
            else:
                status_class = "active"
                icon = "⋯" # loading dots
        else:
            status_class = ""
            icon = str(idx + 1)

        html += f"""
        <div class="step-item {status_class}">
            <div class="step-icon">{icon}</div>
            <div>{name}</div>
        </div>
        """
        if idx < len(steps) - 1:
            html += '<div class="step-arrow">➜</div>'

    html += '</div>'
    return html
```

### 3. 修改 `_run_plan_and_code` 逻辑 (支持 Yield 流式输出)

```python
def _run_plan_and_code(
    task_description: str,
    benchmark_name: str,
    benchmark_description: str,
    dataset_ids_table: List[List[str]],
    progress=gr.Progress()
):
    """
    Generator function.
    Yields: (progress_html, plan_md, plan_raw, code_src)
    """
    # init states
    empty_plan = ""
    empty_code = ""

    # State 0: Start Preview
    yield _render_progress_html(0), empty_plan, empty_plan, empty_code

    progress(0.1, desc="Previewing Dataset Information ...")
    sample, error = _build_sample_from_inputs(
        task_description,
        benchmark_name,
        benchmark_description,
        dataset_ids_table,
    )
    if error:
        # Error state
        err_msg = f"❌ Error during preview: {error}"
        yield _render_progress_html(0, error=True), err_msg, err_msg, ""
        return

    # State 1: Preview Done -> Generating Plan
    yield _render_progress_html(1), empty_plan, empty_plan, empty_code

    progress(0.3, desc="Generating Plan ...")
    plan_text = _generate_plan_from_sample(sample)

    if plan_text.startswith("Planner error") or not plan_text.strip():
        err_msg = f"❌ Planner failed: {plan_text}"
        yield _render_progress_html(1, error=True), err_msg, err_msg, ""
        return

    # State 2: Plan Done -> Generating Code (Show Plan immediately)
    yield _render_progress_html(2), plan_text, plan_text, empty_code

    progress(0.5, desc="Generating Code ...")
    # Pass progress to sub-function if needed, or just let it run
    code_text = _generate_code_from_plan(sample["datasets"], plan_text, progress=progress)

    # State 3: All Done
    yield _render_progress_html(3), plan_text, plan_text, code_text
```

