增加 `detail_msg` 参数，用于显示具体进度文本。

```python
def _render_progress_html(current_step: int, error: bool = False, detail_msg: str = "") -> str:
    """
    current_step: 
    0 = Idle/Previewing
    1 = Plan Generating
    2 = Code Generating
    3 = Done
    """
    steps = ["Data Preview", "Processing Plan", "Code Generation"]

    # 构建图标行
    icons_html = '<div class="step-row">'
    for idx, name in enumerate(steps):
        if idx < current_step:
            status_class = "done"
            icon = "✓"
        elif idx == current_step:
            if error:
                status_class = "active" # 可以改为红色样式
                icon = "✕"
            elif current_step == 3:
                 status_class = "done"
                 icon = "✓"
            else:
                status_class = "active"
                icon = "⋯"
        else:
            status_class = ""
            icon = str(idx + 1)

        icons_html += f"""
        <div class="step-item {status_class}">
            <div class="step-icon">{icon}</div>
            <div>{name}</div>
        </div>
        """
        if idx < len(steps) - 1:
            icons_html += '<div class="step-arrow">➜</div>'
    icons_html += '</div>'

    # 构建状态文字行
    text_html = f'<div class="step-status-text">{detail_msg}</div>'

    return f'<div class="step-container">{icons_html}{text_html}</div>'
```

### 3. 修改 `_run_plan_and_code` 生成器

移除 `progress` 参数（因为不再使用 Gradio 原生进度条），改为通过 `yield` 更新 HTML 组件。

```python
def _run_plan_and_code(
    task_description: str,
    benchmark_name: str,
    benchmark_description: str,
    dataset_ids_table: List[List[str]],
    # progress=gr.Progress()  <-- 移除此参数，不使用原生进度条
):
    """
    Generator function.
    Yields: (process_status_update, plan_md, plan_raw, code_src)
    """
    empty_plan = ""
    empty_code = ""

    # State 0: Start Preview
    msg = "Loading dataset info..."
    yield gr.update(value=_render_progress_html(0, detail_msg=msg), visible=True), empty_plan, empty_plan, empty_code

    sample, error = _build_sample_from_inputs(
        task_description,
        benchmark_name,
        benchmark_description,
        dataset_ids_table,
    )
    if error:
        err_msg = f"❌ Error: {error}"
        yield gr.update(value=_render_progress_html(0, error=True, detail_msg=err_msg)), err_msg, err_msg, ""
        return

    # State 1: Preview Done -> Generating Plan
    msg = "Designing data processing plan with LLM..."
    yield gr.update(value=_render_progress_html(1, detail_msg=msg)), empty_plan, empty_plan, empty_code

    plan_text = _generate_plan_from_sample(sample)

    if plan_text.startswith("Planner error") or not plan_text.strip():
        err_msg = f"❌ Planner failed: {plan_text}"
        yield gr.update(value=_render_progress_html(1, error=True, detail_msg=err_msg)), err_msg, err_msg, ""
        return

    # State 2: Plan Done -> Generating Code
    msg = "Generating executable code..."
    yield gr.update(value=_render_progress_html(2, detail_msg=msg)), plan_text, plan_text, empty_code

    # 注意：这里我们无法获得 _generate_code_from_plan 内部的实时进度(attempt x/4)，
    # 除非重构该函数。为了保持简洁，我们只显示正在生成。
    code_text = _generate_code_from_plan(sample["datasets"], plan_text)

    # State 3: All Done
    msg = "All tasks completed successfully!"
    yield gr.update(value=_render_progress_html(3, detail_msg=msg)), plan_text, plan_text, code_text
```

