def _render_progress_html(current_step: int, error: bool = False, detail_msg: str = "") -> str:
    """
    current_step: 
    0 = Idle/Previewing
    1 = Plan Generating
    2 = Code Generating
    3 = Done
    """
    steps = ["Data Preview", "Processing Plan", "Code Generation"]

    icons_html = '<div class="step-row">'
    for idx, name in enumerate(steps):
