                # 进行中：Blue Pulse
                status_class = "active"
                icon = "⋯"
        else:
            # 未开始：Gray
            status_class = ""
            icon = str(idx + 1)

        icons_html += f"""
        <div class="step-item {status_class}">
            <div class="step-icon">{icon}</div>
            <div>{name}</div>
        </div>
